# Geometry module - base shapes and types
# Provides the base Shape class and ShapeType enum

enum ShapeType:
    Rectangle = 1
    Circle = 2

@abstract
class Shape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @abstract
    def get_type(self) -> ShapeType:
        ...

