# Shapes module - concrete shape implementations
# Provides Rectangle and Circle implementations

from geometry import Shape, ShapeType

class Rectangle(Shape):
    width: float
    height: float
    center_x: int
    center_y: int

    def __init__(self, width: float, height: float, center_x: int, center_y: int):
        self.width = width
        self.height = height
        self.center_x = center_x
        self.center_y = center_y

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def get_type(self) -> ShapeType:
        return ShapeType.Rectangle

    def is_square(self) -> bool:
        return self.width == self.height

class Circle(Shape):
    radius: float
    center_x: int
    center_y: int

    def __init__(self, radius: float, center_x: int, center_y: int):
        self.radius = radius
        self.center_x = center_x
        self.center_y = center_y

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def get_type(self) -> ShapeType:
        return ShapeType.Circle

    def get_diameter(self) -> float:
        return self.radius * 2.0
